}

// 将任意角度归一化到 [-180, 180) 范围
float normalize_angle_to_180(float angle) {
    // 首先归一化到 [0, 360) 范围
    angle = fmodf(angle, 360.0f);
    if (angle < 0) {
        angle += 360.0f;
    }
    
    // 转换到 [-180, 180) 范围
    if (angle > 180.0f) {
        angle -= 360.0f;
    }
    
    return angle;
}


