	//////////////////////////////////////////////将指令按照某个字符串分段存储
uint8_t split_buf(uint8_t *s,uint8_t split_buf[5][12],char sp)
 {
	 uint16_t i = 0, j = 0, num = 0;
	for (i = 0; s[i] != 0; i++)
	{
		if (s[i] != sp)
		{
			split_buf[num][j] = s[i];
			j++;
			if(j>11) break ;
		}
		else 
		{
			num++; j = 0; 
		}
		
	}
	return num+1;
	}


//十六进制字符传转换成16进制数字
uint16_t hex4ToUint16( char hex[4]) {
    uint16_t result = 0;
    
    for(int i = 0; i < 4; i++) {
        char c = toupper(hex[i]);
        uint8_t value = (c >= 'A') ? (c - 'A' + 10) : (c - '0');
        result = (result << 4) | value;
    }
    
    return result;
}
////十六进制数转换成字符串
void uint16ToHex(uint16_t num, char hex[5]) {
    const char hexChars[] = "0123456789ABCDEF";
    hex[0] = hexChars[(num >> 12) & 0xF];
    hex[1] = hexChars[(num >> 8) & 0xF];
    hex[2] = hexChars[(num >> 4) & 0xF];
    hex[3] = hexChars[num & 0xF];
    hex[4] = '\0';
}
//限制范围函数
void limit_max_min(float *value, float max, float min)
{
  if (*value > max) *value = max;
  else if (*value < min) *value = min;
}

// 将任意角度归一化到 [-180, 180) 范围
float normalize_angle_to_180(float angle) {
    // 首先归一化到 [0, 360) 范围
    angle = fmodf(angle, 360.0f);
    if (angle < 0) {
        angle += 360.0f;
    }
    
    // 转换到 [-180, 180) 范围
    if (angle > 180.0f) {
        angle -= 360.0f;
    }
    
    return angle;
}


