 180:uint16_t hex4ToUint16( char hex[4]) {
 181:    uint16_t result = 0;
 182:    
 183:    for(int i = 0; i < 4; i++) {
 184:        char c = toupper(hex[i]);
 185:        uint8_t value = (c >= 'A') ? (c - 'A' + 10) : (c - '0');
 186:        result = (result << 4) | value;
 187:    }
 188:    
 189:    return result;
