 192:void uint16ToHex(uint16_t num, char hex[5]) {
 193:    const char hexChars[] = "0123456789ABCDEF";
 194:    hex[0] = hexChars[(num >> 12) & 0xF];
 195:    hex[1] = hexChars[(num >> 8) & 0xF];
 196:    hex[2] = hexChars[(num >> 4) & 0xF];
