 38:PID_Controller_t speed_pi; //速度环pid
 39:
 40:// 编码器变量
 41:uint16_t  mt6816_count=0;//编码器计数值
 42:uint16_t encoder_last_count = 0;
 43:int32_t encoder_count_accum = 0;
 44:extern uint8_t pos_finish_flag;
 45:extern uint8_t connect_type;
 46:// 编码器PPR
 47:#define MT6816_PPR 16384
 48:// 定时器频率及周期需要你根据硬件具体调整
 49:extern uint16_t angle_zero;
 50:
 51:///PI控制
 52:float PID_Controller_Update(PID_Controller_t *pi, float error)
 53:{
 54:    pi->integral += error * pi->ki;
 55:    // 反积分限幅
 56:    if(pi->integral > pi->output_max) pi->integral = pi->output_max;
 57:    else if(pi->integral < pi->output_min) pi->integral = pi->output_min;
 58:
 59:    float output = pi->kp * error +  pi->integral+pi->kd*(error-pi->last_err );
 60:
 61:    // 输出限幅
 62:    if(output > pi->output_max) output = pi->output_max;
 63:    else if(output < pi->output_min) output = pi->output_min;
 64:    pi->last_err =error ;  
 65:    return output;
 66:}
 67:
 68: ///PI参数初始化
 69:void PID_Controller_Init(PID_Controller_t *pi, float kp, float ki,float kd,float target ,float out_min, float out_max)
 70:{
 71:    pi->kp = kp;
 72:    pi->ki = ki;
 73:	  pi->kd = kd;
 74:	  pi->target =target ;
 75:    pi->integral = 0.0f;
 76:	  if(out_max >4 )out_max =4;
 77:	  if(out_min <-4)out_min =-4;//限幅
 78:    pi->output_min = out_min;
 79:    pi->output_max = out_max;
 80:}
