 83:// 计算编码器差值，考虑编码器计数范围为0~MT6816_PPR-1环绕
 84:int16_t Encoder_GetDiff(uint16_t current_count, uint16_t last_count)
 85:{
 86:    int16_t diff = ((int16_t)current_count - (int16_t)last_count);
 87:
 88:    // 如果差值大于半个计数周期，说明发生了环绕，需校正
 89:    if(diff > (MT6816_PPR / 2))
 90:        diff -= MT6816_PPR;
 91:    else if(diff < -(MT6816_PPR / 2))
 92:        diff += MT6816_PPR;
 93:
 94:    return (int16_t)diff*DIR;
 95:}
 96:
 97:// 读取编码器计数，计算累计计数（处理溢出）
 98:void Encoder_Update(void)
 99:{
100:    int16_t diff = Encoder_GetDiff(mt6816_count , encoder_last_count);
101:    encoder_count_accum += diff;
102:    encoder_last_count = mt6816_count;
103:}
104:
105:void init_encoder_update(void)//初始化计数，需要速度环进行前使用
106:{
107:    encoder_last_count   = mt6816_count; // 以当前值为新的“上一点”
108:    encoder_count_accum  = 0;
109:}
110:
111:// 计算速度（单位rpm），周期为 speed_loop_period 秒
112:float Calculate_Speed(float speed_loop_period)
113:{
114:    float revolutions = (float)encoder_count_accum / MT6816_PPR;
115:    encoder_count_accum = 0;  // 清零累计计数
116:
117:    float speed_rpm = (revolutions / speed_loop_period) * 60.0f;
118:    return speed_rpm;
119:}
