129:float Angle_Normalize(float angle) {
130:    while (angle < 0) angle += 360;
131:    while (angle >= 360) angle -= 360;
132:    return angle;
133:}
134:
135:
136:// 计算角度误差，范围在[-pi, pi]
137:float Angle_Error(float target, float current) {
138:    float diff = target - current;
139:    if (diff > 180) diff -= 360;
140:    else if (diff < -180) diff += 360;
141:    return diff;
142:}
